const https = require('https');
const now = new Date().toISOString();
const token = '7bbe69de41d39e31391d67adda453835aefe5e70ea809d9b3d45981706435d37f39acdd839efeedc';

function nocoGet(path) {
  return new Promise((resolve) => {
    const encodedPath = path.replace(/[가-힣ㄱ-ㅎㅏ-ㅣ]+/g, m => encodeURIComponent(m));
    https.get({ hostname: 'nocodb.pressco21.com', path: '/api/v1/db/data/noco/poey1yrm1r6sthf/' + encodedPath, headers: { 'xc-token': token } }, (res) => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { resolve({ list: [] }); } });
    }).on('error', () => resolve({ list: [] }));
  });
}

try {
  const [apps, files, anns] = await Promise.all([
    nocoGet('m7wl4cjcwsylwvr?sort=-created_at&limit=10'),
    nocoGet('mib4o5cqaufc49y?limit=50'),
    nocoGet('m9pvnifrpmwmbvs?where=(관련도점수,gte,70)&sort=-관련도점수&limit=5')
  ]);

  const appList = (apps.list || []).map(a => ({
    id: a.Id, announcement_title: a.announcement_title, agency: a.agency,
    status: a.status, deadline: a.deadline, total_docs: a.total_docs || 0,
    ready_docs: a.ready_docs || 0, progress_pct: a.progress_pct || 0
  }));

  const fileList = files.list || [];
  const today = new Date();
  let valid = 0, expired = 0, expiring = 0;
  fileList.forEach(f => {
    if (!f.expiry_date) { valid++; return; }
    const exp = new Date(f.expiry_date);
    const days = Math.ceil((exp - today) / 86400000);
    if (days < 0) expired++;
    else if (days <= 30) expiring++;
    else valid++;
  });

  const annList = (anns.list || []).slice(0, 5).map(a => ({
    id: a.Id, title: a['지원사업이름'] || '', agency: a['소관기관'] || '',
    score: a['관련도점수'] || 0, deadline: a['마감일'] || '',
    support_amount: a['예상지원규모'] || '', reason: (a['적합이유'] || '').slice(0, 80)
  }));

  return [{ json: {
    applications: appList,
    common_files: { total: fileList.length, valid, expired, expiring_soon: expiring },
    recent_announcements: annList,
    _generated_at: now
  } }];
} catch(e) {
  return [{ json: {
    applications: [], common_files: { total: 0, valid: 0, expired: 0, expiring_soon: 0 },
    recent_announcements: [], _generated_at: now, _error: e.message
  } }];
}

