// 파일 업로드: binary → /tmp/ 저장 → mc cp → NocoDB 기록
const { execSync } = require('child_process');
const fs = require('fs');
const mc = '/home/node/.n8n/mc';

const items = $input.all();
const binaryKeys = Object.keys(items[0].binary || {});
if (binaryKeys.length === 0) {
  return [{ json: { error: 'No file uploaded' } }];
}

const binaryData = items[0].binary[binaryKeys[0]];
const originalName = binaryData.fileName || 'upload.pdf';
const mimeType = binaryData.mimeType || 'application/pdf';
const fileSize = binaryData.fileSize || 0;

// body에서 file_type 추출
const body = items[0].json.body || items[0].json || {};
const fileType = body.file_type || '기타';

// 파일명 안전하게 변환
const safeName = originalName.replace(/[^a-zA-Z0-9._-]/g, '_');
const timestamp = Date.now();
const minioFileName = timestamp + '_' + safeName;
const tmpPath = '/tmp/' + minioFileName;
const minioPath = 'gov-docs/common/' + minioFileName;

// binary를 파일로 저장
const buf = await this.helpers.getBinaryDataBuffer(0, binaryKeys[0]);
fs.writeFileSync(tmpPath, buf);

// MinIO 업로드
try {
  execSync(mc + ' cp "' + tmpPath + '" "minio/images/' + minioPath + '"', { timeout: 30000 });
} catch(e) {
  return [{ json: { error: 'MinIO upload failed: ' + e.message } }];
}

// 임시 파일 삭제
try { fs.unlinkSync(tmpPath); } catch(e) {}

const fileUrl = 'https://img.pressco21.com/images/' + minioPath;
const now = new Date().toISOString();

return [{ json: {
  file_name: originalName,
  file_type: fileType,
  minio_path: minioPath,
  file_url: fileUrl,
  file_size: buf.length,
  uploaded_at: now,
  is_active: true,
  _action: 'save_to_nocodb'
} }];

