try {
  const [appRes, clRes] = await Promise.all([
    nocoGet('m7wl4cjcwsylwvr?where=(Id,eq,' + appId + ')&limit=1'),
    nocoGet('mfqjk3vc66ui0yg?where=(application_id,eq,' + appId + ')&sort=sort_order&limit=50')
  ]);

  const app = (appRes.list || [])[0] || {};

  // 보관소 파일 조회 (AUTO_COPY 자동 재매칭용)
  const cfRes = await nocoGet('mib4o5cqaufc49y?where=(is_active,eq,1)&limit=50');
  const commonFiles = cfRes.list || [];

  const rawChecklist = clRes.list || [];
  // AUTO_COPY MISSING 항목 자동 재매칭
  let updatedCount = 0;
  for (const c of rawChecklist) {
    if (c.category === 'AUTO_COPY' && c.status === 'MISSING') {
      const match = commonFiles.find(f => f.file_type === c.doc_name);
      if (match) {
        c.status = 'READY';
        c.file_url = match.file_url || '';
        c.common_file_id = match.Id;
        // NocoDB 업데이트
        await nocoReq('PATCH', 'mfqjk3vc66ui0yg/' + c.Id, { status: 'READY', file_url: match.file_url, common_file_id: match.Id });
        updatedCount++;
      }
    }
  }
  // 진행률 재계산
  if (updatedCount > 0) {
    const ready = rawChecklist.filter(c => c.status === 'READY' || c.status === 'SUBMITTED').length;
    const pct = Math.round(ready / rawChecklist.length * 100);
    await nocoReq('PATCH', 'm7wl4cjcwsylwvr/' + appId, { ready_docs: ready, progress_pct: pct });
    app.ready_docs = ready;
    app.progress_pct = pct;
  }

  const checklist = rawChecklist.map(c => ({
    Id: c.Id, doc_name: c.doc_name, category: c.category,
    status: c.status, file_url: c.file_url || '',
    issue_url: c.issue_url || '', issue_guide: c.issue_guide || '',
    ai_template: c.ai_template || '', sort_order: c.sort_order
  }));

  // AI 분석 데이터 조회 (정부지원공고 테이블에서 공고 제목으로 매칭)
  let aiData = {};
  if (app.announcement_title) {
    try {
      const aiRes = await nocoGet('m9pvnifrpmwmbvs?where=' + encodeURIComponent('(지원사업이름,eq,' + app.announcement_title + ')') + '&limit=1');
      const aiRec = (aiRes.list || [])[0];
      if (aiRec) {
        aiData = {
          ai_score: aiRec['관련도점수'] || 0,
          ai_reason: aiRec['적합이유'] || '',
          ai_tip: aiRec['신청팁'] || '',
          ai_qualification: aiRec['신청자격_충족여부'] || '',
          ai_success: aiRec['신청성공가능성'] || '',
          ai_docs: aiRec['필요서류_예측'] || ''
        };
      }
    } catch(e) {}
  }

  return [{ json: {
    application: {
      id: app.Id, announcement_title: app.announcement_title, agency: app.agency,
      status: app.status, deadline: app.deadline, total_docs: app.total_docs,
      ready_docs: app.ready_docs, progress_pct: app.progress_pct,
      submission_method: app.submission_method || '', submission_notes: app.submission_notes || '',
      announcement_url: app.announcement_url || '',
      hwpx_form_url: app.hwpx_form_url || '',
      ...aiData
    },
    checklist
  } }];
} catch(e) {
  return [{ json: { error: e.message } }];
}

