}

function nocoReq(method, path, bodyData) {
  return new Promise((resolve) => {
    const postData = JSON.stringify(bodyData);
    const req = https.request({
      hostname: baseHost, path: basePath + '/' + path, method,
      headers: { 'xc-token': token, 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(postData) }
