    });
    req.on('error', () => resolve({}));
    req.write(postData);
    req.end();
  });
}

function httpPostMultipart(hostname, port, urlPath, filePath, formFields) {
  return new Promise((resolve, reject) => {
    const boundary = '----FormBoundary' + Date.now();
    const fileData = fs.readFileSync(filePath);
    const fileName = filePath.split('/').pop();
    let bodyParts = [];
    bodyParts.push(Buffer.from('--' + boundary + '\r\nContent-Disposition: form-data; name="file"; filename="' + fileName + '"\r\nContent-Type: application/octet-stream\r\n\r\n'));
    bodyParts.push(fileData);
    bodyParts.push(Buffer.from('\r\n'));
    for (const [key, value] of Object.entries(formFields)) {
      bodyParts.push(Buffer.from('--' + boundary + '\r\nContent-Disposition: form-data; name="' + key + '"\r\n\r\n' + value + '\r\n'));
    }
    bodyParts.push(Buffer.from('--' + boundary + '--\r\n'));
    const body = Buffer.concat(bodyParts);
    const req = http.request({
      hostname, port, path: urlPath, method: 'POST',
      headers: { 'Content-Type': 'multipart/form-data; boundary=' + boundary, 'Content-Length': body.length }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const buf = Buffer.concat(chunks);
        const ct = res.headers['content-type'] || '';
        if (ct.includes('json')) {
          try { resolve({ type: 'json', data: JSON.parse(buf.toString()) }); }
          catch(e) { resolve({ type: 'text', data: buf.toString() }); }
        } else {
          resolve({ type: 'binary', data: buf, contentType: ct });
        }
      });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

function callGemini(prompt) {
  return new Promise((resolve, reject) => {
    const payload = JSON.stringify({
      contents: [{ role: 'user', parts: [{ text: prompt }] }],
      generationConfig: { maxOutputTokens: 16384, temperature: 0.3 }
    });
    const req = https.request({
      hostname: 'generativelanguage.googleapis.com',
      path: '/v1beta/models/gemini-2.5-flash:generateContent?key=' + GEMINI_KEY,
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(payload) }
    }, (res) => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        try {
          const j = JSON.parse(data);
          const text = j.candidates[0].content.parts[0].text || '';
          resolve(text);
        } catch(e) { reject(new Error('Gemini parse error: ' + data.slice(0, 200))); }
      });
    });
    req.on('error', reject);
    req.write(payload);
    req.end();
  });
}

