const https = require('https');
const { execSync } = require('child_process');
const token = '7bbe69de41d39e31391d67adda453835aefe5e70ea809d9b3d45981706435d37f39acdd839efeedc';
const baseHost = 'nocodb.pressco21.com';
const basePath = '/api/v1/db/data/noco/poey1yrm1r6sthf';
const mc = '/home/node/.n8n/mc';

const query = $input.first().json.query || {};
const appId = query.id;
if (!appId) return [{ json: { error: 'id required' } }];

function nocoGet(path) {
  return new Promise((resolve) => {
    const encodedPath = path.replace(/[가-힣ㄱ-ㅎㅏ-ㅣ]+/g, m => encodeURIComponent(m));
    https.get({ hostname: baseHost, path: basePath + '/' + encodedPath, headers: { 'xc-token': token } }, (res) => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { resolve({ list: [] }); } });
    }).on('error', () => resolve({ list: [] }));
  });
}

try {
  // 1. Application + Checklist 조회
  const [appRes, clRes] = await Promise.all([
    nocoGet('m7wl4cjcwsylwvr?where=(Id,eq,' + appId + ')&limit=1'),
    nocoGet('mfqjk3vc66ui0yg?where=(application_id,eq,' + appId + ')&sort=sort_order&limit=50')
